head.script:
scwin.MSG_SD_WRN_001 = "통합매출 정보를 생성해야 합니다.";
scwin.MSG_SD_WRN_002 = "출고예정 시간이 형식에 일치하지 않습니다.";
scwin.MSG_SD_WRN_003 = "출고예정 분이 형식에 일치하지 않습니다.";
scwin.MSG_SD_WRN_004 = "확정된 것은 삭제할 수 없습니다.";
scwin.MSG_SD_WRN_005 = "항목을 먼저 선택해야 합니다.";
scwin.MSG_SD_WRN_006 = "확정인 경우 삭제할수 없습니다.";
scwin.MSG_SD_WRN_007 = "오더번호가 다를 경우 삭제할수 없습니다.";
scwin.MSG_SD_WRN_008 = "매출항목 조회결과가 없습니다.";
scwin.MSG_SD_WRN_009 = "원본 데이타가 존재하지 않습니다.";
scwin.MSG_SD_WRN_010 = "분할된 금액이 존재할 경우 삭제할수 없습니다.";
scwin.MSG_SD_WRN_011 = "저장된 상태에서만 금액분할이 가능합니다.";
scwin.MSG_SD_WRN_012 = "분할 금액이 원금액을 초과할수 없습니다.";
scwin.MSG_SD_WRN_013 = "분할 단가가 원단가를 초과할수 없습니다.";
scwin.MSG_SD_WRN_014 = "확정된 것은 금액분할 할수 없습니다.";
scwin.MSG_SD_WRN_015 = "원본 데이타만 금액분할이 가능합니다.";
scwin.MSG_SD_WRN_016 = "저장되지 않은 분할금액이 존재합니다.";
scwin.MSG_SD_WRN_017 = "오더 컨테이너 목록에 존재하지 않는 순번 입니다.";
scwin.MSG_SD_WRN_018 = "출고예정번호가 존재하지 않습니다.";
scwin.MSG_SD_WRN_019 = "실적매출은 삭제할수 없습니다.";
scwin.MSG_SD_WRN_020 = "출고예정번호가 다른 것은 삭제할 수 없습니다.";

scwin.odrNo = "";
scwin.outIntendNo = "";
scwin.delflag = "";
scwin.sellItemCd = "";
scwin.commSeq = 0;
scwin.closeFlag = "";
scwin.fitRow = 0;
scwin.v_bilgLodeptCd = "";
scwin.v_fmlaClsCd = "";
scwin.v_fmlaPatternCd = "";
scwin.prevRow = 0;
scwin.Wt20E = 0;
scwin.Wt20F = 0;
scwin.Wt40E = 0;
scwin.Wt40F = 0;
scwin.Wt45E = 0;
scwin.Wt45F = 0;
scwin.txt_outIntendNo = "";
scwin.ed_odrDcsnYn = "";
scwin.txt_bilgLodeptNm = "";
scwin.txt_dptWrkPlNm = "";
scwin.txt_ctrtNo = "";
scwin.txt_bilgClntNm = "";
scwin.txt_pldgClntNm = "";
scwin.txt_taxnClsCd = "";
scwin.txt_slipPldgNo = "";
scwin.txt_blNo = "";
scwin.txt_bondMcom = "";
scwin.txt_arrvlportDt = "";
scwin.txt_selfClsNm = "";
scwin.txt_wrkPl = "";
scwin.txt_crryoutAdmitNo = "";
scwin.txt_admitDropDt = "";
scwin.txt_whouseClsNm = "";
scwin.txt_line = "";
scwin.txt_outAdjmStsCd = "";
scwin.txt_summary = "";
scwin.txt_fmlaPatternNm = "";
scwin.txt_rmk = "";
scwin.vCurDate = "";
scwin.currentTime = "";

scwin.onpageload = async function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    let now = new Date();
    let hof = now.getHours().toString();
    let mm = now.getMinutes().toString();
    if (hof.length == 1) { hof = "0" + hof; }
    if (mm.length == 1) { mm = "0" + mm; }
    scwin.currentTime = hof + mm;

    scwin.odrNo = $c.data.getParameter() != null && $c.data.getParameter()["odrNo"] != null ? $c.data.getParameter()["odrNo"] : "";
    scwin.outIntendNo = $c.data.getParameter() != null && $c.data.getParameter()["outIntendNo"] != null ? $c.data.getParameter()["outIntendNo"] : "";
};

scwin.onUdcCompleted = async function() {
    rd_prebilgClsCd.setValue("02");
    acb_selectbox1.setValue("06");

    ica_inputCalendar8.setValue(scwin.vCurDate);
    ed_input40.setValue(scwin.currentTime);
    ica_rsltsStdDt.setValue(scwin.vCurDate);

    ed_input11.setValue(0);
    ed_input12.setValue(0);
    ed_input20.setValue(0);
    ed_input21.setValue(0);
    ed_input22.setValue(0);
    ed_input23.setValue(0);

    if (scwin.odrNo != "") {
        ed_outIntendNo.setValue(scwin.outIntendNo);
        // TODO: ed_odrNo is udc_comCode - set code value
        scwin.f_Retrieve("Conn");
    }
};

scwin.f_Retrieve = async function(selFg) {
    dma_odrOutIntend_con.set("odrNo", "");
    dma_odrOutIntend_con.set("outIntendNo", "");

    if (selFg == "Conn") {
        dma_odrOutIntend_con.set("odrNo", ed_odrNo.getValue ? ed_odrNo.getValue() : "");
        dma_odrOutIntend_con.set("outIntendNo", ed_outIntendNo.getValue());
    } else if (selFg == "Enter") {
        dma_odrOutIntend_con.set("odrNo", ed_odrNo.getValue ? ed_odrNo.getValue() : "");
        dma_odrOutIntend_con.set("outIntendNo", "");
    } else if (selFg == "Button") {
        let chk = await $c.gus.cfValidate([ed_outIntendNo]);
        if (!chk) {
            return;
        }
        dma_odrOutIntend_con.set("odrNo", "");
        dma_odrOutIntend_con.set("outIntendNo", ed_outIntendNo.getValue());
    }

    await $c.sbm.execute(sbm_cntrOutIntend_retrieve);
};

scwin.f_Create = async function() {
    $c.gus.cfInitObjects(tbl_search, [ed_odrNo]);

    // TODO: ed_odrNo readOnly handling for udc_comCode

    ds_cntrBulkOutIntend.removeAll();
    ds_cntrBulkOutIntendDetail.removeAll();
    ds_unitySelling.removeAll();

    // TODO: ed_odrNo.setFocus();

    if (rd_prebilgClsCd.getValue() == "01") {
        // TODO: div_fmlaPatternNm1/2 display toggle
    } else {
        // TODO: div_fmlaPatternNm1/2 display toggle
    }
};

scwin.f_Save = async function() {
    let chk1 = await $c.gus.cfValidate([ed_bilgLodeptCd, ed_bilgClntNo, ica_rsltsStdDt, ica_inputCalendar8, ed_input40]);
    if (!chk1) {
        return;
    }

    let chk2 = await $c.gus.cfValidate([gr_cntrBulkOutIntendDetail]);
    if (!chk2) {
        return;
    }

    let chk3 = await $c.gus.cfValidate([gr_unitySelling]);
    if (!chk3) {
        return;
    }

    for (let i = 0; i < ds_cntrBulkOutIntendDetail.getRowCount(); i++) {
        if (ds_cntrBulkOutIntendDetail.getCellData(i, "choice") == "T") {
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt") == "") {
                await $c.gus.cfAlertMsg("오더 컨테이너 목록의 " + (i + 1) + "번째 출고예정일자는 필수항목입니다.");
                ds_cntrBulkOutIntendDetail.setRowPosition(i);
                gr_cntrBulkOutIntendDetail.setFocusedCell(i, "outIntendDt");
                return;
            }
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendHh") == "") {
                await $c.gus.cfAlertMsg("오더 컨테이너 목록의 " + (i + 1) + "번째 출고예정시분은 필수항목입니다.");
                ds_cntrBulkOutIntendDetail.setRowPosition(i);
                gr_cntrBulkOutIntendDetail.setFocusedCell(i, "outIntendHh");
                return;
            }
        }
    }

    let confirmResult = await $c.win.confirm(MSG_CM_CRM_001);
    if (!confirmResult) return;

    ds_cntrBulkOutIntend.setCellData(0, "outIntendNo", scwin.txt_outIntendNo);
    ds_cntrBulkOutIntend.setCellData(0, "prebilgClsCd", rd_prebilgClsCd.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "bilgLodeptCd", ed_bilgLodeptCd.getValue ? ed_bilgLodeptCd.getValue() : "");
    ds_cntrBulkOutIntend.setCellData(0, "bilgClntNo", ed_bilgClntNo.getValue ? ed_bilgClntNo.getValue() : "");
    ds_cntrBulkOutIntend.setCellData(0, "pldgClntNo", ed_pldgClntNo.getValue ? ed_pldgClntNo.getValue() : "");
    ds_cntrBulkOutIntend.setCellData(0, "outIntendDt", ica_inputCalendar8.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "outIntendHh", ed_input40.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "outAdjmPatternCd", acb_selectbox1.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "summary", ed_input30.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "jdgAmt", ed_input24.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "cstmdtAmt", ed_input25.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "spplyAmt", ed_input9.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "vatAmt", ed_input38.getValue());

    // TODO: maxAdptExchRt / maxAdptExchRtDt logic
    let adptExchRt = ds_cntrBulkOutIntend.getCellData(0, "adptExchRt");
    if (adptExchRt <= 0) {
        // TODO: set max exchange rate from ds_unitySelling
    }

    ds_cntrBulkOutIntend.setCellData(0, "fmlaClsCd", scwin.v_fmlaClsCd);
    ds_cntrBulkOutIntend.setCellData(0, "fmlaPatternCd", scwin.v_fmlaPatternCd);

    for (let i = 0; i < ds_cntrBulkOutIntendDetail.getRowCount(); i++) {
        if (ds_cntrBulkOutIntend.getCellData(0, "cntrYn") == "1") {
            ds_cntrBulkOutIntendDetail.setCellData(i, "qtyUnitCd", "VAN");
        } else {
            ds_cntrBulkOutIntendDetail.setCellData(i, "qtyUnitCd", "");
        }
    }

    scwin.f_ChkData();

    for (let k = 0; k < ds_unitySelling.getRowCount(); k++) {
        if (ds_unitySelling.getCellData(k, "choice") == "T") {
            ds_unitySelling.setCellData(k, "bilgClntNo", ed_bilgClntNo.getValue ? ed_bilgClntNo.getValue() : "");
            ds_unitySelling.setCellData(k, "bilgLodeptCd", ed_bilgLodeptCd.getValue ? ed_bilgLodeptCd.getValue() : "");
        }
        if (ds_unitySelling.getCellData(k, "volAmtDivsClsCd") == "C") {
            ds_unitySelling.setCellData(k, "volAmtDivsClsCd", "A");
        }
        ds_unitySelling.setCellData(k, "dcScCd", ds_unitySelling.getCellData(k, "dcScCd").trim());
    }

    if (scwin.txt_outIntendNo == "") {
        ds_cntrBulkOutIntend.setCellData(0, "outAdjmStsCd", "01");
        scwin.prevRow = ds_unitySelling.getRowPosition();
        sbm_cntrOutIntend_save.action = "/ds.sd.odrmgnt.odroutintend.RegistContainerOutIntendCMD.do";
    } else {
        let otherCnt = 0;
        for (let j = 0; j < ds_unitySelling.getRowCount(); j++) {
            if (ds_unitySelling.getRowStatus(j) != "D") {
                if (ds_unitySelling.getCellData(scwin.fitRow, "odrNo") == ds_unitySelling.getCellData(j, "bilgTrgtOdrNo")) {
                    otherCnt++;
                }
            }
            if (otherCnt == 0) {
                ds_unitySelling.setCellData(scwin.fitRow, "volAmtDivsClsCd", "N");
            }
        }
        scwin.prevRow = ds_unitySelling.getRowPosition();
        sbm_cntrOutIntend_save.action = "/ds.sd.odrmgnt.odroutintend.UpdateContainerOutIntendCMD.do";
    }
    await $c.sbm.execute(sbm_cntrOutIntend_save);
};

scwin.f_ChkData = async function() {
    for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
        if (rd_prebilgClsCd.getValue() == "02") {
            if (ds_cntrBulkOutIntend.getCellData(0, "fmlaPatternCd") == "05") {
                if (acb_selectbox1.getValue() == "04") {
                    ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "N");
                    ds_unitySelling.setCellData(i, "outIntendSeq", 0);
                } else if (acb_selectbox1.getValue() == "06") {
                    ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "Y");
                    ds_unitySelling.setCellData(i, "outIntendSeq", 0);
                } else if (acb_selectbox1.getValue() == "05") {
                    ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "Y");
                } else if (acb_selectbox1.getValue() == "09") {
                    ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "Y");
                }
            } else {
                ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "Y");
            }
        } else {
            ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "Y");
        }
    }
};

scwin.f_SumAmt = async function() {
    let sellAmt = 0;
    let vatAmt = 0;
    for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
        if (ds_unitySelling.getCellData(i, "choice") == "T" && ds_unitySelling.getRowStatus(i) != "D") {
            sellAmt = sellAmt + Number(ds_unitySelling.getCellData(i, "sellAmt"));
            vatAmt = vatAmt + Number(ds_unitySelling.getCellData(i, "vatAmt"));
        }
    }
    ed_input9.setValue(sellAmt);
    ed_input38.setValue(vatAmt);
    ed_input32.setValue(sellAmt + vatAmt);
};

scwin.f_PostSumAmt = async function(i) {
    if (i == 0) {
        scwin.Wt20E = 0; scwin.Wt20F = 0; scwin.Wt40E = 0;
        scwin.Wt40F = 0; scwin.Wt45E = 0; scwin.Wt45F = 0;
    }
    if (ds_cntrBulkOutIntendDetail.getCellData(i, "choice") == "T") {
        let sizCd = ds_cntrBulkOutIntendDetail.getCellData(i, "cntrSizCd");
        let feCls = ds_cntrBulkOutIntendDetail.getCellData(i, "fullEmptyClsCd");
        if (sizCd == "20" && feCls == "E") { scwin.Wt20E++; }
        else if (sizCd == "20" && feCls == "F") { scwin.Wt20F++; }
        else if (sizCd == "40" && feCls == "E") { scwin.Wt40E++; }
        else if (sizCd == "40" && feCls == "F") { scwin.Wt40F++; }
        else if (sizCd == "45" && feCls == "E") { scwin.Wt45E++; }
        else if (sizCd == "45" && feCls == "F") { scwin.Wt45F++; }
    }
    ed_input11.setValue(scwin.Wt20E);
    ed_input12.setValue(scwin.Wt20F);
    ed_input20.setValue(scwin.Wt40E);
    ed_input21.setValue(scwin.Wt40F);
    ed_input22.setValue(scwin.Wt45E);
    ed_input23.setValue(scwin.Wt45F);
};

scwin.f_Delete = async function() {
    for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
        if (ds_unitySelling.getCellData(i, "outIntendNo") != "") {
            if (ds_unitySelling.getCellData(i, "outIntendNo") == scwin.txt_outIntendNo && ds_unitySelling.getCellData(i, "dcsnClsCd") != "1") {
                await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_004);
                return;
            }
        }
    }

    let confirmResult = await $c.win.confirm(MSG_CM_CRM_004);
    if (confirmResult == true) {
        scwin.delflag = "DEL";
        sbm_cntrOutIntend_save.action = "/ds.sd.odrmgnt.odroutintend.DeleteContainerOutIntendCMD.do";
        await $c.sbm.execute(sbm_cntrOutIntend_save);
    }
};

scwin.f_AddRow = function() {
    if (ds_unitySelling.getRowCount() < 1) {
        ds_unitySelling.insertRow();
        let rp = ds_unitySelling.getRowPosition();
        let drp = ds_cntrBulkOutIntendDetail.getRowPosition();
        ds_unitySelling.setCellData(rp, "choice", "T");
        ds_unitySelling.setCellData(rp, "sellCommNo", ds_cntrBulkOutIntendDetail.getCellData(drp, "cntrNo"));
        ds_unitySelling.setCellData(rp, "commNm", ds_cntrBulkOutIntendDetail.getCellData(drp, "commNm"));
        ds_unitySelling.setCellData(rp, "odrNo", ds_cntrBulkOutIntend.getCellData(0, "odrNo"));
        ds_unitySelling.setCellData(rp, "outIntendNo", ds_cntrBulkOutIntend.getCellData(0, "outIntendNo"));
        ds_unitySelling.setCellData(rp, "updateClsCd", "");
        ds_unitySelling.setCellData(rp, "commSeq", ds_cntrBulkOutIntendDetail.getCellData(drp, "commSeq"));
        ds_unitySelling.setCellData(rp, "sellVol", 1);
        ds_unitySelling.setCellData(rp, "prebilgYn", 1);
        ds_unitySelling.setCellData(rp, "prebilgCreatYn", 1);
        ds_unitySelling.setCellData(rp, "sellSeq", 0);
        ds_unitySelling.setCellData(rp, "dcsnClsCd", "1");
        ds_unitySelling.setCellData(rp, "dcsnClsNm", "미확인");
        ds_unitySelling.setCellData(rp, "addRowYn", "Y");
        ds_unitySelling.setCellData(rp, "sellUnitCd", "VAN");
        ds_unitySelling.setCellData(rp, "mrn", ds_cntrBulkOutIntend.getCellData(0, "mrn"));
        ds_unitySelling.setCellData(rp, "msn", ds_cntrBulkOutIntend.getCellData(0, "msn"));
        ds_unitySelling.setCellData(rp, "hsn", ds_cntrBulkOutIntend.getCellData(0, "hsn"));
        ds_unitySelling.setCellData(rp, "bilgLodeptCd", ds_cntrBulkOutIntend.getCellData(0, "bilgLodeptCd"));
        ds_unitySelling.setCellData(rp, "sellLodeptCd", ds_cntrBulkOutIntend.getCellData(0, "sellLodeptCd"));
        ds_unitySelling.setCellData(rp, "lineCd", ds_cntrBulkOutIntend.getCellData(0, "lineCd"));
        ds_unitySelling.setCellData(rp, "wrkStDt", ds_cntrBulkOutIntend.getCellData(0, "odrDt"));
        ds_unitySelling.setCellData(rp, "bilgClntNo", ds_cntrBulkOutIntend.getCellData(0, "bilgClntNo"));
        ds_unitySelling.setCellData(rp, "ctrtClntNo", ds_cntrBulkOutIntend.getCellData(0, "ctrtClntNo"));
        ds_unitySelling.setCellData(rp, "reqClntNo", ds_cntrBulkOutIntend.getCellData(0, "reqClntNo"));
        ds_unitySelling.setCellData(rp, "taxnClsCd", ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd"));
        ds_unitySelling.setCellData(rp, "odrDt", ds_cntrBulkOutIntend.getCellData(0, "odrDt"));
        ds_unitySelling.setCellData(rp, "vsslCd", ds_cntrBulkOutIntend.getCellData(0, "vsslCd"));
        ds_unitySelling.setCellData(rp, "portcnt", ds_cntrBulkOutIntend.getCellData(0, "portcnt"));
        ds_unitySelling.setCellData(rp, "dptDistrictCd", ds_cntrBulkOutIntend.getCellData(0, "dptDistrictCd"));
        ds_unitySelling.setCellData(rp, "arvDistrictCd", ds_cntrBulkOutIntend.getCellData(0, "arvDistrictCd"));
        ds_unitySelling.setCellData(rp, "impExpDomesticClsCd", ds_cntrBulkOutIntend.getCellData(0, "impExpDomesticClsCd"));
        ds_unitySelling.setCellData(rp, "ctrtNo", ds_cntrBulkOutIntend.getCellData(0, "ctrtNo"));
        ds_unitySelling.setCellData(rp, "ctrtWrkPathSeq", ds_cntrBulkOutIntend.getCellData(0, "ctrtWrkPathSeq"));
    } else {
        let curPos = ds_unitySelling.getRowPosition();
        ds_unitySelling.insertRow(curPos + 1);
        let newPos = ds_unitySelling.getRowPosition();
        let colCount = ds_unitySelling.getColumnCount();
        for (let ci = 0; ci < colCount; ci++) {
            let colId = ds_unitySelling.getColumnID(ci);
            if (colId == "dcsnClsCd") {
                ds_unitySelling.setCellData(newPos, "dcsnClsCd", "1");
            } else if (colId == "dcsnClsNm") {
                ds_unitySelling.setCellData(newPos, "dcsnClsNm", "미확인");
            } else {
                ds_unitySelling.setCellData(newPos, colId, ds_unitySelling.getCellData(newPos - 1, colId));
            }
        }
        ds_unitySelling.setCellData(newPos, "choice", "T");
        ds_unitySelling.setCellData(newPos, "sellSeq", 0);
        ds_unitySelling.setCellData(newPos, "addRowYn", "Y");
        ds_unitySelling.setCellData(newPos, "sellAmt", 0);
        ds_unitySelling.setCellData(newPos, "vatAmt", 0);
        ds_unitySelling.setCellData(newPos, "sumSellAmt", 0);
        ds_unitySelling.setCellData(newPos, "prebilgYn", 1);
        ds_unitySelling.setCellData(newPos, "prebilgCreatYn", 1);
        ds_unitySelling.setCellData(newPos, "updateClsCd", "");
        ds_unitySelling.setCellData(newPos, "outIntendNo", "");
        ds_unitySelling.setCellData(newPos, "odrNo", ds_cntrBulkOutIntend.getCellData(0, "odrNo"));
    }

    // TODO: $c.gus.cfShowTotalRows(totalRows2, ds_unitySelling.getRowCount());
    gr_unitySelling.setReadOnly("grid", false);
};

scwin.f_DelRow = async function() {
    let rp = ds_unitySelling.getRowPosition();
    if (rp < 0) return;

    if (ds_unitySelling.getCellData(rp, "dcsnClsCd") != "1") {
        await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_006);
        return;
    }
    if (ds_unitySelling.getCellData(rp, "prebilgYn") != "1") {
        await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_019);
        return;
    }
    if (ds_unitySelling.getCellData(rp, "odrNo") != ds_cntrBulkOutIntend.getCellData(0, "odrNo")) {
        await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_007);
        return;
    }
    if (ds_unitySelling.getCellData(rp, "outIntendNo") != "") {
        if (ds_unitySelling.getCellData(rp, "outIntendNo") != scwin.txt_outIntendNo) {
            await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_020);
            return;
        }
    }

    let divsCls = ds_unitySelling.getCellData(rp, "volAmtDivsClsCd");
    if (divsCls == "A" || divsCls == "C") {
        if (ds_unitySelling.getCellData(rp, "bilgTrgtOdrNo") == "") {
            let isHaveChild = false;
            for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
                if (ds_unitySelling.getCellData(rp, "odrNo") == ds_unitySelling.getCellData(i, "bilgTrgtOdrNo") &&
                    ds_unitySelling.getCellData(rp, "sellSeq") == ds_unitySelling.getCellData(i, "bilgTrgtSellSeq") &&
                    ds_unitySelling.getRowStatus(i) != "D") {
                    isHaveChild = true;
                    break;
                }
            }
            if (isHaveChild) {
                await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_010);
                return;
            }
        } else {
            ds_unitySelling.setCellData(scwin.fitRow, "sellUpr", Number(ds_unitySelling.getCellData(scwin.fitRow, "sellUpr")) + Number(ds_unitySelling.getCellData(rp, "sellUpr")));
            ds_unitySelling.setCellData(scwin.fitRow, "sellAmt", Number(ds_unitySelling.getCellData(scwin.fitRow, "sellAmt")) + Number(ds_unitySelling.getCellData(rp, "sellAmt")));
            ds_unitySelling.setCellData(scwin.fitRow, "vatAmt", Number(ds_unitySelling.getCellData(scwin.fitRow, "vatAmt")) + Number(ds_unitySelling.getCellData(rp, "vatAmt")));
            ds_unitySelling.setCellData(scwin.fitRow, "sumSellAmt", Number(ds_unitySelling.getCellData(scwin.fitRow, "sumSellAmt")) + Number(ds_unitySelling.getCellData(rp, "sumSellAmt")));
        }
    }

    ds_unitySelling.removeRow(rp);
    scwin.f_SumAmt();
};

scwin.f_AppendSellItem = async function(sellItemCd, commSeq, close) {
    if ((sellItemCd == undefined || sellItemCd == "") && commSeq != 0) {
        if (ds_cntrBulkOutIntendDetail.getCellData(ds_cntrBulkOutIntendDetail.getRowPosition(), "choice") == "F") {
            await $c.gus.cfAlertMsg("해당 CNTR-NO를 선택해야 합니다.");
            return;
        }
    }

    let chk = await $c.gus.cfValidate([ica_inputCalendar8, ed_input40]);
    if (!chk) return;

    scwin.f_RetrieveSellItem(scwin.v_bilgLodeptCd, scwin.v_fmlaClsCd, scwin.v_fmlaPatternCd);

    for (let k = 0; k < ds_cntrBulkOutIntendDetail.getRowCount(); k++) {
        if (acb_selectbox1.getValue() == "04" || acb_selectbox1.getValue() == "06") {
            if (ds_cntrBulkOutIntendDetail.getCellData(k, "inCrryinoutDt") != "") {
                let diffDay = $c.date.diffDate(ds_cntrBulkOutIntendDetail.getCellData(k, "inCrryinoutDt"), ica_inputCalendar8.getValue());
                if (diffDay > 10) {
                    if (Number(ds_cntrBulkOutIntendDetail.getCellData(k, "jdgAmt")) < 1) {
                        await $c.gus.cfAlertMsg("감정가는 필수 입력 항목입니다.");
                        return;
                    }
                }
            }
        }

        if (close == "TRUE") {
            scwin.closeFlag = "TRUE";
        } else {
            scwin.closeFlag = "FALSE";
        }

        dma_appendSellItem_con.set("outIntendNo", scwin.txt_outIntendNo);
        dma_appendSellItem_con.set("odrNo", ds_cntrBulkOutIntend.getCellData(0, "odrNo"));
        dma_appendSellItem_con.set("bilgLodeptCd", ed_bilgLodeptCd.getValue ? ed_bilgLodeptCd.getValue() : "");
        dma_appendSellItem_con.set("fmlaClsCd", scwin.v_fmlaClsCd);
        dma_appendSellItem_con.set("fmlaPatternCd", scwin.v_fmlaPatternCd);
        dma_appendSellItem_con.set("outAdjmPatternCd", acb_selectbox1.getValue());
        dma_appendSellItem_con.set("jdgAmt", ed_input24.getValue());
        dma_appendSellItem_con.set("cstmdtAmt", ed_input25.getValue());

        if ((sellItemCd == undefined || sellItemCd == "") && commSeq == 0) {
            dma_appendSellItem_con.set("sellItemCd", "");
            dma_appendSellItem_con.set("outIntendDt", ds_cntrBulkOutIntendDetail.getCellData(k, "outIntendDt"));
            dma_appendSellItem_con.set("outIntendHh", ds_cntrBulkOutIntendDetail.getCellData(k, "outIntendHh"));
            dma_appendSellItem_con.set("commSeq", ds_cntrBulkOutIntendDetail.getCellData(k, "commSeq"));
        } else if ((sellItemCd == undefined || sellItemCd == "") && commSeq != 0) {
            let drp = ds_cntrBulkOutIntendDetail.getRowPosition();
            dma_appendSellItem_con.set("sellItemCd", "CNTR");
            dma_appendSellItem_con.set("outIntendDt", ds_cntrBulkOutIntendDetail.getCellData(drp, "outIntendDt"));
            dma_appendSellItem_con.set("outIntendHh", ds_cntrBulkOutIntendDetail.getCellData(drp, "outIntendHh"));
            dma_appendSellItem_con.set("commSeq", ds_cntrBulkOutIntendDetail.getCellData(drp, "commSeq"));
        } else {
            let drp = ds_cntrBulkOutIntendDetail.getRowPosition();
            dma_appendSellItem_con.set("sellItemCd", sellItemCd);
            dma_appendSellItem_con.set("outIntendDt", ds_cntrBulkOutIntendDetail.getCellData(drp, "outIntendDt"));
            dma_appendSellItem_con.set("outIntendHh", ds_cntrBulkOutIntendDetail.getCellData(drp, "outIntendHh"));
            dma_appendSellItem_con.set("commSeq", commSeq);
        }

        if (dma_appendSellItem_con.get("outIntendDt") < ica_inputCalendar8.getValue()) {
            dma_appendSellItem_con.set("outIntendDt", ica_inputCalendar8.getValue());
        }
    }

    await $c.sbm.execute(sbm_appendSellItem_retrieve);
};

scwin.f_CancelSellItem = async function() {
    let confirmResult = await $c.win.confirm(MSG_CM_CRM_011);
    if (!confirmResult) return;

    let cnt = ds_unitySelling.getRowCount();
    for (let i = cnt - 1; i >= 0; i--) {
        if (ds_unitySelling.getCellData(i, "sellSeq") == "0") {
            ds_unitySelling.removeRow(i);
        }
    }

    // TODO: cfShowTotalRows

    if (ds_cntrBulkOutIntend.getCellData(0, "outIntendNo").length > 0) {
        for (let j = 0; j < ds_unitySelling.getRowCount(); j++) {
            if (ds_unitySelling.getCellData(j, "outIntendNo") == ds_cntrBulkOutIntend.getCellData(0, "outIntendNo")) {
                ds_unitySelling.setRowStatus(j, "D");
            }
        }
        await $c.sbm.execute(sbm_cancelSellItem_save);
    }
};

