scwin.f_AmtDivision = async function() {
    if (ds_unitySelling.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_009);
        return;
    }

    let rp = ds_unitySelling.getRowPosition();

    if (ds_unitySelling.getCellData(rp, "bilgTrgtOdrNo") != "") {
        await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_015);
        return;
    }

    let isChild = false;
    for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
        if (ds_unitySelling.getCellData(rp, "odrNo") == ds_unitySelling.getCellData(i, "bilgTrgtOdrNo") &&
            ds_unitySelling.getCellData(rp, "sellSeq") == ds_unitySelling.getCellData(i, "bilgTrgtSellSeq") &&
            ds_unitySelling.getCellData(i, "volAmtDivsClsCd") == "C") {
            isChild = true;
            break;
        }
    }

    if (isChild) {
        await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_016);
        return;
    }

    if (ds_unitySelling.getRowStatus(rp) != "R") {
        await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_011);
        return;
    }

    if (ds_unitySelling.getCellData(rp, "dcsnClsCd") != "1") {
        await $c.gus.cfAlertMsg(scwin.MSG_SD_WRN_014);
        return;
    }

    ds_unitySelling.insertRow(rp + 1);
    let newPos = ds_unitySelling.getRowPosition();
    let colCount = ds_unitySelling.getColumnCount();
    for (let j = 0; j < colCount; j++) {
        let colId = ds_unitySelling.getColumnID(j);
        if (colId == "sellAmt") {
            ds_unitySelling.setCellData(newPos, "sellAmt", 0);
        } else if (colId == "vatAmt") {
            ds_unitySelling.setCellData(newPos, "vatAmt", 0);
        } else if (colId == "sumSellAmt") {
            ds_unitySelling.setCellData(newPos, "sumSellAmt", 0);
        } else if (colId == "sellUpr") {
            ds_unitySelling.setCellData(newPos, "sellUpr", 0);
        } else {
            ds_unitySelling.setCellData(newPos, colId, ds_unitySelling.getCellData(newPos - 1, colId));
        }
    }

    ds_unitySelling.setCellData(newPos, "bilgTrgtSellSeq", ds_unitySelling.getCellData(newPos - 1, "sellSeq"));
    ds_unitySelling.setCellData(newPos, "bilgTrgtOdrNo", ds_unitySelling.getCellData(newPos - 1, "odrNo"));
    ds_unitySelling.setCellData(newPos, "volAmtDivsClsCd", "C");
    ds_unitySelling.setCellData(newPos, "choice", "F");
    ds_unitySelling.setCellData(newPos, "outIntendNo", "");
    ds_unitySelling.setCellData(newPos, "outIntendSeq", "");
    ds_unitySelling.setCellData(newPos, "sellSeq", 0);

    scwin.f_findParentRow(newPos);

    ds_unitySelling.setCellData(newPos - 1, "volAmtDivsClsCd", "A");

    gr_unitySelling.setFocusedCell(newPos, "sellAmt");
    gr_unitySelling.setReadOnly("grid", false);
};

