scwin.f_Round = async function(Num, Position, Base) {
    if (Position == 0) {
        return Math.round(Num);
    } else if (Position > 0) {
        let cipher = "1";
        for (let i = 0; i < Position; i++) cipher = cipher + "0";
        let no = Number(cipher);
        if (Base == "F") {
            return Math.round(Num * no) / no;
        } else {
            return Math.round(Num / no) * no;
        }
    } else {
        await $c.gus.cfAlertMsg("자릿수는 정수로만 구분합니다.");
        return false;
    }
};

scwin.f_calSc = async function(row) {
    let offInRate = 0;
    let devanningRate = 0;
    let paperSell20 = 0;
    let paperSell40 = 0;
    let paperSell = 0;
    let bExistPaperSell = false;
    let rate = 0;
    let scRt = 0;
    let sellVol = 0;
    let sellItemCdVal = ds_unitySelling.getCellData(row, "sellItemCd");

    for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
        if (ds_unitySelling.getCellData(i, "sellItemCd") == "0050") { offInRate = Number(ds_unitySelling.getCellData(i, "sellAmt")); }
        if (ds_unitySelling.getCellData(i, "sellItemCd") == "0179") { devanningRate = Number(ds_unitySelling.getCellData(i, "sellAmt")); }
        if (ds_unitySelling.getCellData(i, "sellItemCd") == "0278") { paperSell20 = Number(ds_unitySelling.getCellData(i, "sellAmt")); bExistPaperSell = true; }
        if (ds_unitySelling.getCellData(i, "sellItemCd") == "0279") { paperSell40 = Number(ds_unitySelling.getCellData(i, "sellAmt")); bExistPaperSell = true; }
    }

    paperSell = (paperSell20 >= paperSell40) ? paperSell20 : paperSell40;

    if (sellItemCdVal == "0093" || sellItemCdVal == "0094" || sellItemCdVal == "0095" || sellItemCdVal == "0096" || sellItemCdVal == "0097") {
        rate = (offInRate + devanningRate) * 0.1;
    } else if (sellItemCdVal == "0088") {
        scRt = Number(ds_unitySelling.getCellData(row, "scRt"));
        rate = (offInRate + devanningRate) * scRt / 100;
    } else if (sellItemCdVal == "0098") {
        rate = (offInRate + devanningRate) * 0.5;
    } else if (sellItemCdVal == "0089") {
        if (bExistPaperSell) { rate = paperSell * 0.5; } else { rate = (offInRate + devanningRate) * 0.5; }
    } else if (sellItemCdVal == "0090") {
        if (bExistPaperSell) { rate = paperSell * 0.25; } else { rate = (offInRate + devanningRate) * 0.25; }
    }

    for (let j = 0; j < ds_unitySelling.getRowCount(); j++) {
        let si = ds_unitySelling.getCellData(j, "sellItemCd");
        if (si == "0050" || si == "0179" || si == "0278" || si == "0279") {
            ds_unitySelling.setCellData(row, "sellVol", ds_unitySelling.getCellData(j, "sellVol"));
            ds_unitySelling.setCellData(row, "sellUnitCd", ds_unitySelling.getCellData(j, "sellUnitCd"));
            ds_unitySelling.setCellData(row, "unitClsCd", ds_unitySelling.getCellData(j, "unitClsCd"));
            break;
        }
    }

    sellVol = Number(ds_unitySelling.getCellData(row, "sellVol"));
    ds_unitySelling.setCellData(row, "sellAmt", rate);
    if (sellVol == 0) {
        ds_unitySelling.setCellData(row, "sellUpr", 0);
    } else {
        ds_unitySelling.setCellData(row, "sellUpr", rate / sellVol);
    }
    ds_unitySelling.setCellData(row, "vatAmt", rate * 0.1);
};

