        }
        if (sameYn == "Y") {
            let msg = "관리거래처입니다\n\n관리거래처 변경으로 문제발생 시 책임을 물을 수 있습니다.\n\n책임을 물어도 변경하시겠습니까?";
            let confirmResult = await $c.win.confirm(msg);
            if (!confirmResult) {
                // TODO: clear ed_bilgClntNo, txt_bilgClntNm
            }
        }
    }
};

