// ds_cntrBulkOutIntend OnLoadCompleted
scwin.ds_cntrBulkOutIntend_onloadcompleted = async function(e) {
    let rowcnt = ds_cntrBulkOutIntend.getRowCount();
    if (rowcnt > 0) {
        scwin.txt_outIntendNo = ds_cntrBulkOutIntend.getCellData(0, "outIntendNo");
        // TODO: set ed_bilgLodeptCd via udc_comCode
        scwin.txt_bilgLodeptNm = ds_cntrBulkOutIntend.getCellData(0, "bilgLodeptNm");
        scwin.txt_dptWrkPlNm = ds_cntrBulkOutIntend.getCellData(0, "dptWrkPlNm");
        // TODO: set ed_odrNo
        scwin.ed_odrDcsnYn = ds_cntrBulkOutIntend.getCellData(0, "odrDcsnYn");

        if (scwin.ed_odrDcsnYn == "1") {
            $c.gus.cfEnableBtnOnly([btn_trigger16]);
        } else {
            $c.gus.cfDisableBtnOnly([btn_trigger16]);
        }

        scwin.txt_ctrtNo = ds_cntrBulkOutIntend.getCellData(0, "ctrtNo");

        if (scwin.txt_outIntendNo == "") {
            rd_prebilgClsCd.setValue("02");
            acb_selectbox1.setValue("06");
        } else {
            acb_selectbox1.setValue(ds_cntrBulkOutIntend.getCellData(0, "outAdjmPatternCd"));
            rd_prebilgClsCd.setValue(ds_cntrBulkOutIntend.getCellData(0, "prebilgClsCd"));
        }

        // TODO: set ed_pldgClntNo, ed_bilgClntNo via udc_comCode
        scwin.txt_pldgClntNm = ds_cntrBulkOutIntend.getCellData(0, "pldgClntNm");
        scwin.txt_bilgClntNm = ds_cntrBulkOutIntend.getCellData(0, "bilgClntNm");

        let taxnClsCd = ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd");
        if (taxnClsCd == "01") { scwin.txt_taxnClsCd = "과세"; }
        else if (taxnClsCd == "02") { scwin.txt_taxnClsCd = "영세"; }
        else if (taxnClsCd == "03") { scwin.txt_taxnClsCd = "기타"; }

        scwin.txt_slipPldgNo = ds_cntrBulkOutIntend.getCellData(0, "sellVatNo") + "/" + ds_cntrBulkOutIntend.getCellData(0, "pldgMgntNo");
        scwin.txt_blNo = ds_cntrBulkOutIntend.getCellData(0, "blNo");
        scwin.txt_bondMcom = ds_cntrBulkOutIntend.getCellData(0, "bondTransExpireDt") + "/" + ds_cntrBulkOutIntend.getCellData(0, "mcomAssgnClsCd");
        let arrvlportDt = ds_cntrBulkOutIntend.getCellData(0, "arrvlportDt");
        scwin.txt_arrvlportDt = arrvlportDt.substring(0, 4) + "/" + arrvlportDt.substring(4, 6) + "/" + arrvlportDt.substring(6, 8);
        ed_input24.setValue(ds_cntrBulkOutIntend.getCellData(0, "jdgAmt"));
        ed_input25.setValue(ds_cntrBulkOutIntend.getCellData(0, "cstmdtAmt"));
        scwin.txt_selfClsNm = ds_cntrBulkOutIntend.getCellData(0, "selfClsNm");
        scwin.txt_wrkPl = ds_cntrBulkOutIntend.getCellData(0, "dptWrkPlNm") + "-" + ds_cntrBulkOutIntend.getCellData(0, "arvWrkPlNm");
        scwin.txt_crryoutAdmitNo = ds_cntrBulkOutIntend.getCellData(0, "crryoutAdmitNo");
        scwin.txt_admitDropDt = ds_cntrBulkOutIntend.getCellData(0, "admitDropDt");
        scwin.txt_line = ds_cntrBulkOutIntend.getCellData(0, "lineCd") + "/" + ds_cntrBulkOutIntend.getCellData(0, "vsslCd") + "/" + ds_cntrBulkOutIntend.getCellData(0, "portcnt");

        let outAdjmStsCd = ds_cntrBulkOutIntend.getCellData(0, "outAdjmStsCd");
        if (outAdjmStsCd == "01") { scwin.txt_outAdjmStsCd = "생성"; }
        else if (outAdjmStsCd == "02") { scwin.txt_outAdjmStsCd = "담보"; }
        else if (outAdjmStsCd == "03") { scwin.txt_outAdjmStsCd = "계산서"; }
        else { ds_cntrBulkOutIntend.setCellData(0, "outAdjmStsCd", "01"); scwin.txt_outAdjmStsCd = "생성"; }

        scwin.txt_summary = ds_cntrBulkOutIntend.getCellData(0, "summary");

        if (ds_cntrBulkOutIntend.getCellData(0, "outIntendDt") == "") {
            ica_inputCalendar8.setValue(scwin.vCurDate);
        } else {
            ica_inputCalendar8.setValue(ds_cntrBulkOutIntend.getCellData(0, "outIntendDt"));
        }
        if (ds_cntrBulkOutIntend.getCellData(0, "outIntendHh") == "") {
            ed_input40.setValue(scwin.currentTime);
        } else {
            ed_input40.setValue(ds_cntrBulkOutIntend.getCellData(0, "outIntendHh"));
        }

        ed_input9.setValue(ds_cntrBulkOutIntend.getCellData(0, "spplyAmt"));
        ed_input38.setValue(ds_cntrBulkOutIntend.getCellData(0, "vatAmt"));
        ed_input32.setValue(Number(ds_cntrBulkOutIntend.getCellData(0, "spplyAmt")) + Number(ds_cntrBulkOutIntend.getCellData(0, "vatAmt")));
        ed_input31.setValue(ds_cntrBulkOutIntend.getCellData(0, "pldgAmt"));
        scwin.txt_whouseClsNm = ds_cntrBulkOutIntend.getCellData(0, "whouseClsNm") + "/" + ds_cntrBulkOutIntend.getCellData(0, "arvDtl");
        ed_input10.setValue(ds_cntrBulkOutIntend.getCellData(0, "packCnt"));
        ed_input39.setValue($c.gus.cfConvert2Weight(ds_cntrBulkOutIntend.getCellData(0, "totWt"), "KG", "TON"));
        ed_input33.setValue(ds_cntrBulkOutIntend.getCellData(0, "totCbm"));
        scwin.txt_rmk = ds_cntrBulkOutIntend.getCellData(0, "rmk");

        if (ds_cntrBulkOutIntend.getCellData(0, "prebilgClsCd") == "01") {
            // TODO: lc_fmlaPatternCd setValue
        } else {
            scwin.txt_fmlaPatternNm = ds_cntrBulkOutIntend.getCellData(0, "fmlaPatternNm");
        }

        scwin.f_ChgprebilgClsCd();
        scwin.f_ChgoutAdjmPatternCd();

        // TODO: ed_odrNo readOnly

        scwin.v_bilgLodeptCd = ed_bilgLodeptCd.getValue ? ed_bilgLodeptCd.getValue() : "";
        scwin.v_fmlaClsCd = ds_cntrBulkOutIntend.getCellData(0, "fmlaClsCd");
        scwin.v_fmlaPatternCd = ds_cntrBulkOutIntend.getCellData(0, "fmlaPatternCd");

        if (scwin.txt_outIntendNo == "") {
            let odrKndCd = ds_cntrBulkOutIntend.getCellData(0, "odrKndCd");
            let sellClntClsCd = ds_cntrBulkOutIntend.getCellData(0, "sellClntClsCd");
            if (odrKndCd == "C1" || odrKndCd == "C3" || (odrKndCd == "C2" && sellClntClsCd == "01")) {
                rd_prebilgClsCd.setValue("01");
                scwin.v_fmlaClsCd = "03";
                scwin.v_fmlaPatternCd = "04";
            }
        }

        scwin.f_RetrieveSellItem(scwin.v_bilgLodeptCd, scwin.v_fmlaClsCd, scwin.v_fmlaPatternCd);

        // TODO: button enable/disable based on outAdjmStsCd
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

// ds_cntrBulkOutIntendDetail OnLoadCompleted
scwin.ds_cntrBulkOutIntendDetail_onloadcompleted = function(e) {
    let rowcnt = ds_cntrBulkOutIntendDetail.getRowCount();
    if (rowcnt > 0) {
        scwin.f_DivAllAmt();
        for (let i = 0; i < rowcnt; i++) {
            ds_cntrBulkOutIntendDetail.setCellData(i, "qty", 1);
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "choice") == "T") {
                if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt") == "") {
                    ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendDt", ica_inputCalendar8.getValue());
                }
                if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendHh") == "") {
                    ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendHh", ed_input40.getValue());
                }
            }
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt") != "" && ds_cntrBulkOutIntendDetail.getCellData(i, "outCrryinoutDt") != "") {
                ds_cntrBulkOutIntendDetail.setCellData(i, "overCnt", $c.date.diffDate(ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt"), ds_cntrBulkOutIntendDetail.getCellData(i, "outCrryinoutDt")));
            }
            scwin.f_PostSumAmt(i);
        }
    }
    // TODO: $c.gus.cfShowTotalRows(totalRows, rowcnt);
};

// ds_unitySelling OnLoadCompleted
scwin.ds_unitySelling_onloadcompleted = function(e) {
    scwin.f_RetrieveSellUnitCd();
    let rowcnt = ds_unitySelling.getRowCount();
    // TODO: $c.gus.cfShowTotalRows(totalRows2, rowcnt);

    if (rowcnt > 0) {
