    // TODO: $c.gus.cfGoPrevPosition(ds_unitySelling, scwin.prevRow);
};

// ds_appendSellItem OnLoadCompleted
scwin.ds_appendSellItem_onloadcompleted = function(e) {
    let rowcnt = ds_appendSellItem.getRowCount();
    if (rowcnt > 0) {
        let app_mod = "";
        for (let app_idx = 0; app_idx < ds_appendSellItem.getRowCount(); app_idx++) {
            app_mod = "";
            for (let org_idx = 0; org_idx < ds_unitySelling.getRowCount(); org_idx++) {
                if (scwin.closeFlag == "TRUE") {
                    let colCount = ds_unitySelling.getColumnCount();
                    let rp = ds_unitySelling.getRowPosition();
                    for (let j = 0; j < colCount; j++) {
                        let colId = ds_unitySelling.getColumnID(j);
                        ds_unitySelling.setCellData(rp, colId, ds_appendSellItem.getCellData(app_idx, colId));
                    }
                    app_mod = "수정";
                    break;
                }
                if (ds_appendSellItem.getCellData(app_idx, "strRateYn") == "0") {
                    if (ds_unitySelling.getCellData(org_idx, "sellItemCd") == ds_appendSellItem.getCellData(app_idx, "sellItemCd") &&
                        ds_unitySelling.getCellData(org_idx, "commSeq") == ds_appendSellItem.getCellData(app_idx, "commSeq") &&
                        ds_unitySelling.getCellData(org_idx, "dcScCd") == ds_appendSellItem.getCellData(app_idx, "dcScCd")) {
                        app_mod = "수정";
                        break;
                    }
                } else if (ds_appendSellItem.getCellData(app_idx, "strRateYn") == "1") {
                    if (ds_unitySelling.getCellData(org_idx, "sellItemCd") == ds_appendSellItem.getCellData(app_idx, "sellItemCd") &&
                        ds_unitySelling.getCellData(org_idx, "commSeq") == ds_appendSellItem.getCellData(app_idx, "commSeq") &&
                        ds_unitySelling.getCellData(org_idx, "dcScCd") == ds_appendSellItem.getCellData(app_idx, "dcScCd") &&
                        ds_unitySelling.getCellData(org_idx, "wrkEndDt") == ds_appendSellItem.getCellData(app_idx, "wrkEndDt")) {
                        app_mod = "수정";
                        break;
                    }
                }
            }
            if (app_mod != "수정") {
                ds_unitySelling.insertRow();
                let rp = ds_unitySelling.getRowPosition();
                let colCount = ds_unitySelling.getColumnCount();
                for (let j = 0; j < colCount; j++) {
                    let colId = ds_unitySelling.getColumnID(j);
                    ds_unitySelling.setCellData(rp, colId, ds_appendSellItem.getCellData(app_idx, colId));
                }
            }
        }
        // TODO: $c.gus.cfShowTotalRows(totalRows2, ds_unitySelling.getRowCount());
        gr_unitySelling.setReadOnly("grid", false);
    }
};

// Grid events
scwin.gr_cntrBulkOutIntendDetail_oncellclick = function(rowIndex, columnIndex, columnId) {
    if (columnId == "choice") {
        if (ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "choice") == "T") {
            ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "outIntendNo", scwin.txt_outIntendNo);
            if (ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outIntendDt") == "") {
                ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "outIntendDt", ica_inputCalendar8.getValue());
            }
            if (ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outIntendHh") == "") {
                ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "outIntendHh", ed_input40.getValue());
            }
            if (ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outIntendDt") != "" && ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outCrryinoutDt") != "") {
                ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "overCnt", $c.date.diffDate(ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outIntendDt"), ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outCrryinoutDt")));
            }
        } else {
            ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "outIntendDt", "");
            ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "outIntendHh", "");
            ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "overCnt", "");
        }
        for (let i = 0; i < ds_cntrBulkOutIntendDetail.getRowCount(); i++) {
            scwin.f_PostSumAmt(i);
        }
    }
    if (rowIndex >= 0 && columnId == "cntrNo" && ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "cntrNo") != "") {
        scwin.f_cntrNoDetail();
    }
};

scwin.gr_unitySelling_oncellclick = function(rowIndex, columnIndex, columnId) {
    if (columnId == "choice") {
        if (ds_unitySelling.getCellData(rowIndex, "choice") == "T") {
            if (ds_unitySelling.getCellData(rowIndex, "outIntendNo") == "") {
                ds_unitySelling.setCellData(rowIndex, "outIntendNo", ds_cntrBulkOutIntend.getCellData(0, "outIntendNo"));
                ds_unitySelling.setCellData(rowIndex, "outIntendSeq", ds_unitySelling.getCellData(rowIndex, "outIntendSeq"));
            }
            ds_unitySelling.setCellData(rowIndex, "sellWrkRsltsClsCd", "05");
        } else {
            ds_unitySelling.setCellData(rowIndex, "outIntendNo", "");
            ds_unitySelling.setCellData(rowIndex, "outIntendSeq", "");
            ds_unitySelling.setCellData(rowIndex, "sellWrkRsltsClsCd", "");
        }
        scwin.f_SumAmt();
    }
};

